  1→/**
  2→ * Title Extraction
  3→ * Extracts potential recipe title from OCR text using heuristics or semantic embeddings
  4→ */
  5→
  6→import { cosineSimilarity } from "./embeddings";
  7→
  8→export type EmbedFn = (text: string) => Promise<Array<number>>;
  9→
 10→const TITLE_REFERENCE =
 11→  "recipe name, dish title, name of the food, nazwa przepisu, nazwa dania";
 12→const HEADER_REFERENCE =
 13→  "ingredients list, cooking directions, section heading, składniki, przygotowanie, sposób wykonania";
 14→const NOISE_REFERENCE =
 15→  "page number, table of contents, book footer, garbled text";
 16→
 17→/**
 18→ * Measurement units commonly found in ingredient lists
 19→ */
 20→const MEASUREMENT_PATTERNS = [
 21→  "cup",
 22→  "cups",
 23→  "tbsp",
 24→  "tsp",
 25→  "tablespoon",
 26→  "teaspoon",
 27→  "oz",
 28→  "lb",
 29→  "gram",
 30→  "grams",
 31→  "kg",
 32→  "ml",
 33→  "liter",
 34→  "pinch",
 35→  "dash",
 36→  "handful",
 37→];
 38→
 39→/**
 40→ * Patterns that identify recipe metadata lines (not titles)
 41→ */
 42→const METADATA_PATTERNS = [
 43→  /^(SERVES?|MAKES?|YIELDS?)\b/i,
 44→  /^(PREP(ARATION)?|COOK(ING)?|PROOF|RISING|FERMENTATION|REST(ING)?)\s*(AND\s*)?(COOK(ING)?)?\s*TIME/i,
 45→  /^SAMPLE\s+SCHEDULE\b/i,
 46→  /^BULK\s+FERMENTATION\b/i,
 47→  /^(THIS\s+RECIPE\s+)?MAKES\b/i,
 48→];
 49→
 50→/**
 51→ * Single-word non-title words — standalone OCR fragments unlikely to be recipe titles
 52→ */
 53→const NON_TITLE_WORDS = new Set([
 54→  "the", "and", "for", "but", "not", "you", "all", "can", "are", "was",
 55→  "has", "his", "her", "its", "our", "who", "how", "may", "new", "now",
 56→  "old", "see", "way", "did", "get", "let", "say", "she", "too", "use",
 57→  "buns", "with",
 58→]);
 59→
 60→function looksLikeIngredient(line: string): boolean {
 61→  const lowerLine = line.toLowerCase();
 62→  return MEASUREMENT_PATTERNS.some((pattern) => lowerLine.includes(pattern));
 63→}
 64→
 65→function startsWithNumber(line: string): boolean {
 66→  return /^\s*\d/.test(line);
 67→}
 68→
 69→function isAllCaps(line: string): boolean {
 70→  const letters = line.replace(/[^a-zA-Z]/g, "");
 71→  return letters.length > 0 && letters === letters.toUpperCase();
 72→}
 73→
 74→function looksLikeMetadata(text: string): boolean {
 75→  return METADATA_PATTERNS.some((pattern) => pattern.test(text.trim()));
 76→}
 77→
 78→function isLikelyGarbled(text: string): boolean {
 79→  const letters = text.replace(/[^a-zA-Z]/g, "");
 80→  if (letters.length < 2) return true;
 81→
 82→  // Check vowel ratio — English/Polish text typically has 30–50% vowels
 83→  const vowels = letters.replace(/[^aeiouAEIOUyYąęóĄĘÓ]/g, "").length;
 84→  const vowelRatio = vowels / letters.length;
 85→  if (vowelRatio < 0.15 || vowelRatio > 0.85) return true;
 86→
 87→  // Single orphaned word ≤3 letters that isn't a common word
 88→  const words = text.trim().split(/\s+/);
 89→  const COMMON_SHORT = new Set([
 90→    "the", "and", "for", "but", "not", "you", "all", "can", "had", "her",
 91→    "was", "one", "our", "out", "are", "has", "his", "how", "its", "may",
 92→    "new", "now", "old", "see", "way", "who", "did", "get", "let", "say",
 93→    "she", "too", "use",
 94→  ]);
 95→  if (words.length === 1 && letters.length <= 3 && !COMMON_SHORT.has(text.trim().toLowerCase())) {
 96→    return true;
 97→  }
 98→
 99→  // Recipe titles never start with a lowercase letter
100→  if (/^[a-z]/.test(text.trim())) {
101→    return true;
102→  }
103→
104→  // Mid-text sentence boundary (". " followed by a letter) — body text fragment spliced from multiple sentences
105→  const trimmed = text.trim();
106→  if (/\.\s+[a-zA-Z]/.test(trimmed) && !trimmed.endsWith(")")) {
107→    return true;
108→  }
109→
110→  // Multi-word candidate containing a garbled OCR fragment: a short lowercase word that isn't a known short word
111→  if (words.length >= 2) {
112→    const commonShort2 = new Set([
113→      "a", "i", "of", "or", "to", "in", "on", "is", "it", "an",
114→      "as", "at", "by", "do", "go", "if", "no", "so", "up", "we",
115→      "w", "z",  // Polish prepositions
116→    ]);
117→    const hasGarbledWord = words.some(
118→      (w) =>
119→        /^[a-z]/.test(w) &&
120→        w.replace(/[^a-z]/g, "").length <= 2 &&
121→        !commonShort2.has(w.toLowerCase())
122→    );
123→    if (hasGarbledWord) {
124→      return true;
125→    }
126→  }
127→
128→  return false;
129→}
130→
131→function passesHardFilters(text: string): boolean {
132→  if (text.length < 3 || text.length > 80) return false;
133→  if (looksLikeIngredient(text)) return false;
134→  if (startsWithNumber(text)) return false;
135→  if (looksLikeMetadata(text)) return false;
136→  if (isLikelyGarbled(text)) return false;
137→  // Single-word non-title fragments
138→  const words = text.trim().split(/\s+/);
139→  if (words.length === 1 && NON_TITLE_WORDS.has(text.trim().toLowerCase())) return false;
140→  return true;
141→}
142→
143→/**
144→ * Detect initial burst of short garbled lines.
145→ * Returns the index of the first non-garbled or long line.
146→ */
147→function findBurstEnd(lines: Array<{ text: string }>): number {
148→  let i = 0;
149→  while (i < lines.length && lines[i].text.length < 20 && isLikelyGarbled(lines[i].text)) {
150→    i++;
151→  }
152→  return i;
153→}
154→
155→function wordCount(text: string): number {
156→  return text.split(/\s+/).filter((w) => w.length > 0).length;
157→}
158→
159→/**
160→ * Build candidate strings from lines: single lines plus multi-line joins (2-3 consecutive).
161→ * Skips initial burst of short garbled lines. Scans all remaining lines. Caps at 25.
162→ */
163→export type CandidateOrigin = "single" | "2-line" | "3-line";
164→
165→function buildCandidates(
166→  lines: Array<string>
167→): Array<{ text: string; position: number; origin: CandidateOrigin }> {
168→  const nonEmptyLines: Array<{ text: string; index: number }> = [];
169→
170→  for (let i = 0; i < lines.length; i++) {
171→    const trimmed = lines[i].trim();
172→    if (trimmed.length > 0) {
173→      nonEmptyLines.push({ text: trimmed, index: i });
174→    }
175→  }
176→
177→  const burstEnd = findBurstEnd(nonEmptyLines);
178→  const candidates: Array<{ text: string; position: number; origin: CandidateOrigin }> = [];
179→  const seen = new Set<string>();
180→
181→  for (let i = burstEnd; i < nonEmptyLines.length; i++) {
182→    const line = nonEmptyLines[i];
183→
184→    // Single line
185→    if (passesHardFilters(line.text)) {
186→      const norm = line.text.toLowerCase();
187→      if (!seen.has(norm)) {
188→        seen.add(norm);
189→        candidates.push({ text: line.text, position: line.index, origin: "single" });
190→      }
191→    }
192→
193→    // 2-line join
194→    if (i + 1 < nonEmptyLines.length) {
195→      const joined2 = `${line.text} ${nonEmptyLines[i + 1].text}`;
196→      if (passesHardFilters(joined2)) {
197→        const norm = joined2.toLowerCase();
198→        if (!seen.has(norm)) {
199→          seen.add(norm);
200→          candidates.push({ text: joined2, position: line.index, origin: "2-line" });
201→        }
202→      }
203→    }
204→
205→    // 3-line join
206→    if (i + 2 < nonEmptyLines.length) {
207→      const joined3 = `${line.text} ${nonEmptyLines[i + 1].text} ${nonEmptyLines[i + 2].text}`;
208→      if (passesHardFilters(joined3)) {
209→        const norm = joined3.toLowerCase();
210→        if (!seen.has(norm)) {
211→          seen.add(norm);
212→          candidates.push({ text: joined3, position: line.index, origin: "3-line" });
213→        }
214→      }
215→    }
216→  }
217→
218→  // Pre-filter to 25 before embedding calls: prefer ALL_CAPS and short candidates.
219→  // Position-based scoring handles final ranking.
220→  if (candidates.length > 25) {
221→    const prioritized = candidates.slice().sort((a, b) => {
222→      const aAllCaps = isAllCaps(a.text) ? 0 : 1;
223→      const bAllCaps = isAllCaps(b.text) ? 0 : 1;
224→      if (aAllCaps !== bAllCaps) return aAllCaps - bAllCaps;
225→      const aShort = wordCount(a.text) <= 5 ? 0 : 1;
226→      const bShort = wordCount(b.text) <= 5 ? 0 : 1;
227→      return aShort - bShort;
228→    });
229→    return prioritized.slice(0, 25);
230→  }
231→
232→  return candidates;
233→}
234→
235→// Module-level cache for reference embeddings
236→let cachedTitleRefEmbedding: Array<number> | null = null;
237→let cachedHeaderRefEmbedding: Array<number> | null = null;
238→let cachedNoiseRefEmbedding: Array<number> | null = null;
239→
240→export function _resetEmbeddingCacheForTests(): void {
241→  cachedTitleRefEmbedding = null;
242→  cachedHeaderRefEmbedding = null;
243→  cachedNoiseRefEmbedding = null;
244→}
245→
246→export async function extractTitleWithEmbeddings(
247→  text: string,
248→  embed: EmbedFn
249→): Promise<string | undefined> {
250→  if (!text || text.trim().length === 0) {
251→    return undefined;
252→  }
253→
254→  const lines = text.split("\n");
255→  const candidates = buildCandidates(lines);
256→
257→  if (candidates.length === 0) {
258→    return undefined;
259→  }
260→
261→  // Cache reference embeddings
262→  if (!cachedTitleRefEmbedding) {
263→    cachedTitleRefEmbedding = await embed(TITLE_REFERENCE);
264→  }
265→  if (!cachedHeaderRefEmbedding) {
266→    cachedHeaderRefEmbedding = await embed(HEADER_REFERENCE);
267→  }
268→  if (!cachedNoiseRefEmbedding) {
269→    cachedNoiseRefEmbedding = await embed(NOISE_REFERENCE);
270→  }
271→
272→  // Find ALL_CAPS candidates with ≥2 words where every significant word has ≥4 alpha letters.
273→  // Insignificant tokens (≤1 alpha letter: "/", "&", "+", ":", "D)", etc.) are filtered before
274→  // the check so that multi-line joins with continuation punctuation still qualify.
275→  const isStructuralHeading = (c: { text: string }): boolean => {
276→    if (!isAllCaps(c.text) || wordCount(c.text) < 2) return false;
277→    const sigWords = c.text.trim().split(/\s+/).filter((w) => w.replace(/[^A-Z]/g, "").length > 1);
278→    return sigWords.length >= 2 && sigWords.every((w) => w.replace(/[^A-Z]/g, "").length >= 4);
279→  };
280→
281→  // Pass 1: compute rawScore for all candidates (embedding quality signal)
282→  const rawScored: Array<{ text: string; position: number; origin: CandidateOrigin; rawScore: number; embedding: Array<number> }> = [];
283→  for (const candidate of candidates) {
284→    const embedding = await embed(candidate.text);
285→    const titleSim = cosineSimilarity(embedding, cachedTitleRefEmbedding);
286→    const headerSim = cosineSimilarity(embedding, cachedHeaderRefEmbedding);
287→    const noiseSim = cosineSimilarity(embedding, cachedNoiseRefEmbedding);
288→    const rawScore = titleSim - Math.max(headerSim, noiseSim);
289→    rawScored.push({ text: candidate.text, position: candidate.position, origin: candidate.origin, rawScore, embedding });
290→  }
291→
292→  // Select baseHeading by embedding quality (rawScore), not position.
293→  // This prevents OCR-garbled fragments from claiming the structural heading slot.
294→  const structuralCandidates = rawScored.filter((s) => isStructuralHeading(s));
295→
296→  // Penalize structural headings with truncated OCR words:
297→  // if "FRON" appears and another heading has "SAFFRON", "FRON" is likely garbled.
298→  for (const sc of structuralCandidates) {
299→    const sigWords = sc.text.split(/\s+/).filter((w) => w.replace(/[^A-Z]/g, "").length >= 4);
300→    for (const other of structuralCandidates) {
301→      if (other === sc) continue;
302→      const otherSigWords = other.text.split(/\s+/).filter((w) => w.replace(/[^A-Z]/g, "").length >= 4);
303→      const hasTruncation = sigWords.some((w) =>
304→        otherSigWords.some((ow) => ow !== w && ow.length > w.length && ow.endsWith(w))
305→      );
306→      if (hasTruncation) {
307→        sc.rawScore -= 0.15;
308→        break;
309→      }
310→    }
311→  }
312→
313→  const bestStructural = structuralCandidates.length > 0
314→    ? structuralCandidates.reduce((a, b) => a.rawScore > b.rawScore ? a : b)
315→    : null;
316→  const baseHeading = bestStructural ?? undefined;
317→
318→  // When the best structural heading has a continuation on the next line introduced by a
319→  // punctuation token (/, &, +, :, or parenthesis), prefer the longer 2-line join as the
320→  // complete heading. E.g. "SAFFRON WHEAT BUNS WITH QUARK" + "/ COTTAGE CHEESE (VARIATION D)".
321→  // Guard: the remainder after the prefix must start with a continuation character to avoid
322→  // merging two separate consecutive recipe titles (FINNISH MILK FLATBREADS stays separate
323→  // from FINNISH POTATO FLATBREADS because "FINNISH" does not start with a continuation token).
324→  const firstStructuralHeading = baseHeading && (
325→    rawScored.find((c) => {
326→      if (!isStructuralHeading(c)) return false;
327→      const hLower = baseHeading.text.toLowerCase();
328→      const cLower = c.text.toLowerCase();
329→      return cLower.startsWith(hLower + " ") && /^[/&+:(]/.test(cLower.slice(hLower.length + 1));
330→    }) ?? baseHeading
331→  );
332→
333→  // Pass 2: apply bonuses
334→  const scored: Array<{ text: string; position: number; origin: CandidateOrigin; score: number; rawScore: number; baseScore: number; thresholdScore: number }> = rawScored.map((rs) => {
335→    // Position factor: multiplicative tiebreaker — amplifies existing signal, doesn't replace it
336→    const relativePosition = rs.position / lines.length;
337→    const positionFactor = relativePosition < 0.5
338→      ? 1.0 + 0.12 * (1 - relativePosition * 2)
339→      : 1.0;
340→
341→    // ALL_CAPS bonus: recipe books use ALL_CAPS for titles and section headings
342→    const allCapsBonus = isAllCaps(rs.text) && rs.text.replace(/[^a-zA-Z]/g, "").length >= 4
343→      ? 0.08
344→      : 0;
345→
346→    // Structural heading bonus: best ALL_CAPS heading (or its continuation join) is almost always the recipe title
347→    const structuralBonus = firstStructuralHeading && rs.text === firstStructuralHeading.text ? 0.10 : 0;
348→
349→    // thresholdScore excludes structural bonus so the bonus doesn't inflate the threshold
350→    // and prevent equally-valid structural headings from passing on multi-recipe pages.
351→    const thresholdScore = rs.rawScore + allCapsBonus;
352→    // baseScore excludes position factor — used for diagnostics and ranking
353→    const baseScore = rs.rawScore + allCapsBonus + structuralBonus;
354→    const score = rs.rawScore * positionFactor + allCapsBonus + structuralBonus;
355→    return { text: rs.text, position: rs.position, origin: rs.origin, score, rawScore: rs.rawScore, baseScore, thresholdScore };
356→  });
357→
358→  if (scored.length === 0) {
359→    return undefined;
360→  }
361→
362→  // Use thresholdScore (excludes structural bonus) so the structural bonus doesn't inflate
363→  // the threshold and block equally-valid headings on multi-recipe pages.
364→  const bestThresholdScore = Math.max(...scored.map((s) => s.thresholdScore));
365→  const threshold = Math.max(0.08, bestThresholdScore * 0.7);
366→
367→  // Filter candidates above threshold
368→  let selected = scored.filter((s) => s.score >= threshold);
369→
370→  // Remove word-boundary prefixes of firstStructuralHeading when the heading itself survived
371→  // the threshold. Cases:
372→  //   ARAYES case:  firstStructuralHeading = "ARAYES SHRAK" (2-word join qualifies; "ARAYES"
373→  //     alone = 1 word, so it never qualified). Filter removes "ARAYES" so dedup keeps the join.
374→  //   SAFFRON case: baseHeading was the partial line; continuation logic above upgraded
375→  //     firstStructuralHeading to the full join. Filter removes the partial so dedup keeps join.
376→  // Safety: only fires when the complete heading itself is in selected (passed the threshold).
377→  if (firstStructuralHeading && selected.some((s) => s.text === firstStructuralHeading.text)) {
378→    const fshLower = firstStructuralHeading.text.toLowerCase();
379→    selected = selected.filter((s) => {
380→      if (s.text === firstStructuralHeading.text) return true;
381→      const sLower = s.text.toLowerCase();
382→      // Remove s if it is a space-delimited prefix of the structural heading
383→      return !fshLower.startsWith(sLower + " ");
384→    });
385→  }
386→
387→  // Protect continuation joins: when a multi-line join survived the threshold and its second
388→  // part starts with a continuation character, remove the single-line prefix so the dedup
389→  // "shorter wins" rule doesn't destroy the complete join.
390→  // E.g. "Baked Eggs with Feta, Harissa Tomato Sauce" is removed when
391→  // "Baked Eggs with Feta, Harissa Tomato Sauce & Coriander" also survived (continuation: &).
392→  // Safety: only fires for joins whose continuation starts with /&+:( — digit continuations
393→  // like "Pierogi Ruskie 200g mąki" are NOT protected, so dedup correctly keeps the shorter form.
394→  const survivingJoins = selected.filter((s) => s.origin === "2-line" || s.origin === "3-line");
395→  if (survivingJoins.length > 0) {
396→    selected = selected.filter((s) => {
397→      if (s.origin !== "single") return true;
398→      const sLower = s.text.toLowerCase();
399→      return !survivingJoins.some((j) => {
400→        const jLower = j.text.toLowerCase();
401→        if (!jLower.startsWith(sLower + " ")) return false;
402→        const remainder = jLower.slice(sLower.length + 1);
403→        return /^[/&+:(]/.test(remainder);
404→      });
405→    });
406→  }
407→
408→  // Deduplicate: if one title is a substring of another, keep the shorter (more focused) one.
409→  // DO NOT CHANGE THIS LOGIC — it has been incorrectly "improved" by the title-loop 5 times.
410→  // The tests require shorter wins: "Pierogi Ruskie" over "Pierogi Ruskie 200g mąki 3 ziemniaki".
411→  // The pre-filter above handles the conflicting case (structural heading prefix removal) so that
412→  // the incomplete prefix line is never present here when the complete join is in selected.
413→  selected = selected.filter((a) => {
414→    const aLower = a.text.toLowerCase();
415→    return !selected.some(
416→      (b) =>
417→        b !== a &&
418→        aLower.includes(b.text.toLowerCase()) &&
419→        b.text.length < a.text.length
420→    );
421→  });
422→
423→  // Multi-title guard: only join multiple candidates with "+" when there is
424→  // structural evidence of a multi-recipe page (≥2 ALL_CAPS headings).
425→  // A single ALL_CAPS title among mixed-case survivors is a single-recipe page —
426→  // collapse to the highest-scoring candidate.
427→  // Zero ALL_CAPS survivors → mixed-case multi-title page → keep all.
428→  if (selected.length > 1) {
429→    const allCapsSelected = selected.filter((s) => isAllCaps(s.text));
430→    if (allCapsSelected.length >= 2) {
431→      selected = allCapsSelected;
432→    } else if (allCapsSelected.length === 1) {
433→      selected = [selected.reduce((a, b) => (a.score > b.score ? a : b))];
434→    }
435→  }
436→
437→  // Cap at 3, sort by document position
438→  selected.sort((a, b) => a.position - b.position);
439→  selected = selected.slice(0, 3);
440→
441→  if (selected.length === 0) {
442→    return undefined;
443→  }
444→
445→  return selected.map((s) => s.text).join(" + ");
446→}
447→
448→/**
449→ * Extract potential recipe title from OCR text (sync heuristic fallback)
450→ */
451→export function extractTitle(text: string): string | undefined {
452→  if (!text || text.trim().length === 0) {
453→    return undefined;
454→  }
455→
456→  const lines = text.split("\n").map((line) => line.trim());
457→
458→  for (const line of lines) {
459→    if (line.length === 0) continue;
460→    if (line.length < 3 || line.length > 50) continue;
461→    if (looksLikeIngredient(line)) continue;
462→    if (isAllCaps(line)) continue;
463→    if (startsWithNumber(line)) continue;
464→    return line;
465→  }
466→
467→  return undefined;
468→}
