  lines: Array<string>
): Array<{ text: string; position: number }> {
```

**After:**
```ts
export type CandidateOrigin = "single" | "2-line" | "3-line";

function buildCandidates(
  lines: Array<string>
): Array<{ text: string; position: number; origin: CandidateOrigin }> {
```

Tag each `candidates.push(...)` call:
